package com.linkedin.gms.factory.common;

import java.util.HashMap;
import java.util.Map;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Slf4j
@Configuration
public class LocalCassandraSessionConfigFactory {

  @Value("${cassandra.datasourceUsername}")
  private String datasourceUsername;

  @Value("${cassandra.datasourcePassword}")
  private String datasourcePassword;

  @Value("${cassandra.hosts}")
  private String hosts;

  @Value("${cassandra.port}")
  private String port;

  @Value("${cassandra.datacenter}")
  private String datacenter;

  @Value("${cassandra.keyspace}")
  private String keyspace;

  @Value("${cassandra.useSsl}")
  private String useSsl;

  @Bean(name = "gmsCassandraServiceConfig")
  protected Map<String, String> createInstance() {
    return new HashMap<String, String>() {
      {
        put("username", datasourceUsername);
        put("password", datasourcePassword);
        put("hosts", hosts);
        put("port", port);
        put("datacenter", datacenter);
        put("keyspace", keyspace);
        put("useSsl", useSsl);
      }
    };
  }
}

package com.linkedin.gms.factory.entity;

import com.linkedin.metadata.entity.DeleteEntityService;
import com.linkedin.metadata.entity.EntityService;
import com.linkedin.metadata.graph.GraphService;
import com.linkedin.metadata.search.EntitySearchService;
import com.linkedin.metadata.utils.aws.S3Util;
import com.linkedin.metadata.utils.metrics.MetricUtils;
import javax.annotation.Nonnull;
import javax.annotation.Nullable;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Import;

@Configuration
@Import({EntityServiceFactory.class})
public class DeleteEntityServiceFactory {
  @Autowired
  @Qualifier("entityService")
  private EntityService<?> _entityService;

  @Autowired
  @Qualifier("graphService")
  private GraphService _graphService;

  @Autowired
  @Qualifier("entitySearchService")
  private EntitySearchService _entitySearchService;

  @Autowired(required = false)
  @Qualifier("s3Util")
  @Nullable
  private S3Util _s3Util;

  @Autowired(required = false)
  @Nullable
  private MetricUtils _metricUtils;

  @Bean(name = "deleteEntityService")
  @Nonnull
  protected DeleteEntityService createDeleteEntityService() {
    return new DeleteEntityService(
        _entityService, _graphService, _entitySearchService, _s3Util, _metricUtils);
  }
}

package graphql.kickstart.autoconfigure.web.servlet;

import jakarta.servlet.http.HttpSession;
import jakarta.websocket.server.HandshakeRequest;
import java.util.UUID;
import org.springframework.security.web.csrf.HttpSessionCsrfTokenRepository;

class WsSessionCsrfTokenRepository implements WsCsrfTokenRepository {

  private static final String DEFAULT_CSRF_PARAMETER_NAME = "_csrf";

  private static final String DEFAULT_CSRF_TOKEN_ATTR_NAME =
      HttpSessionCsrfTokenRepository.class.getName().concat(".CSRF_TOKEN");

  private String sessionAttributeName = DEFAULT_CSRF_TOKEN_ATTR_NAME;

  @Override
  public void saveToken(WsCsrfToken token, HandshakeRequest request) {
    HttpSession session = (HttpSession) request.getHttpSession();
    if (session != null) {
      if (token == null) {
        session.removeAttribute(this.sessionAttributeName);
      } else {
        session.setAttribute(this.sessionAttributeName, token);
      }
    }
  }

  @Override
  public WsCsrfToken loadToken(HandshakeRequest request) {
    HttpSession session = (HttpSession) request.getHttpSession();
    if (session == null) {
      return null;
    }
    return (WsCsrfToken) session.getAttribute(this.sessionAttributeName);
  }

  @Override
  public WsCsrfToken generateToken(HandshakeRequest request) {
    return new DefaultWsCsrfToken(UUID.randomUUID().toString(), DEFAULT_CSRF_PARAMETER_NAME);
  }
}

public class MapStepRegistry implements StepRegistry {

	private final ConcurrentMap<String, Map<String, Step>> map = new ConcurrentHashMap<>();

	@Override
	public void register(String jobName, Collection<Step> steps) throws DuplicateJobException {
		Assert.notNull(jobName, "The job name cannot be null.");
		Assert.notNull(steps, "The job steps cannot be null.");

		final Map<String, Step> jobSteps = new HashMap<>();
		for (Step step : steps) {
			jobSteps.put(step.getName(), step);
		}
		final Object previousValue = map.putIfAbsent(jobName, jobSteps);
		if (previousValue != null) {
			throw new DuplicateJobException(
					"A job configuration with this name [" + jobName + "] was already registered");
		}
	}

	@Override
	public void unregisterStepsFromJob(String jobName) {
		Assert.notNull(jobName, "Job configuration must have a name.");
		map.remove(jobName);
	}

	@Override
	@Nullable public Step getStep(String jobName, String stepName) {
		Assert.notNull(jobName, "The job name cannot be null.");
		Assert.notNull(stepName, "The step name cannot be null.");
		if (!map.containsKey(jobName)) {
			return null;
		}
		else {
			final Map<String, Step> jobSteps = map.get(jobName);
			if (jobSteps.containsKey(stepName)) {
				return jobSteps.get(stepName);
			}
			else {
				return null;
			}
		}
	}

}

package com.giffing.bucket4j.spring.boot.starter.cache.infinispan;

import com.giffing.bucket4j.spring.boot.starter.core.cache.AbstractCacheResolverTemplate;
import com.giffing.bucket4j.spring.boot.starter.core.cache.AsyncCacheResolver;
import io.github.bucket4j.distributed.proxy.AbstractProxyManager;
import io.github.bucket4j.grid.infinispan.Bucket4jInfinispan;
import org.infinispan.AdvancedCache;
import org.infinispan.Cache;
import org.infinispan.functional.FunctionalMap;
import org.infinispan.functional.impl.FunctionalMapImpl;
import org.infinispan.functional.impl.ReadWriteMapImpl;
import org.infinispan.manager.CacheContainer;

public class InfinispanCacheResolver extends AbstractCacheResolverTemplate<String> implements AsyncCacheResolver {

    private final CacheContainer cacheContainer;

    public InfinispanCacheResolver(CacheContainer cacheContainer) {
        this.cacheContainer = cacheContainer;
    }

    @Override
    public String castStringToCacheKey(String key) {
        return key;
    }

    @Override
    public boolean isAsync() {
        return true;
    }

    @Override
    public AbstractProxyManager<String> getProxyManager(String cacheName) {
        Cache<String, byte[]> cache = cacheContainer.getCache(cacheName);
        return Bucket4jInfinispan.entryProcessorBasedBuilder(toMap(cache)).build();
    }

    private static FunctionalMap.ReadWriteMap<String, byte[]> toMap(Cache<String, byte[]> cache) {
        AdvancedCache<String, byte[]> advancedCache = cache.getAdvancedCache();
        FunctionalMapImpl<String, byte[]> functionalMap = FunctionalMapImpl.create(advancedCache);
        return ReadWriteMapImpl.create(functionalMap);
    }
}
